3	import { User } from '../entities/user.entity';
4	import { Dashboard, DashboardOptions, getDashboard } from './financial.service';
5	import { AppDataSource } from '../data-source';
6	
7	export type FinancialStatement = {
8	  id: number;
9	  user: {
10	    id: string;
11	    name: string;
12	    email: string;
13	  };
14	  data: Dashboard;
15	  createdAt: Date;
16	};
17	
18	const financialStatementRepository = AppDataSource.getRepository(FinancialStatementEntity);
19	
20	export const findStatementById = async (id: number): Promise<FinancialStatement | null> => {
21	  // join with user
22	  const statement = await financialStatementRepository.findOne({
23	    where: {
24	      id,
25	    },
26	    relations: ['user'],
27	  });
28	  if (!statement) {
29	    return null;
30	  }
31	
32	  return {
33	    id: statement.id,
34	    user: {
35	      id: statement.user.id,
36	      name: statement.user.name,
37	      email: statement.user.email,
38	    },
39	    data: statement.data,
40	    createdAt: statement.createdAt,
41	  };
42	};
43	
44	export const generateStatement = async (
45	  manager: EntityManager,
46	  options: DashboardOptions,
47	): Promise<FinancialStatement> => {
48	  const user = await manager.getRepository(User).findOne({
49	    where: {
50	      id: options.userId,
51	    },
52	  });
53	  if (!user) {
54	    throw new Error('User not found');
55	  }
56	  const dashboard = await getDashboard(options);
57	
58	  const savedStatement = await manager.getRepository(FinancialStatementEntity).save({
59	    userId: user.id,
60	    data: dashboard,
61	    createdAt: new Date(),
62	  });
63	
64	  return {
65	    id: savedStatement.id,
