1	import { Between, Repository } from 'typeorm';
2	import { UTCDate } from '@date-fns/utc';
3	import { addMonths, endOfMonth, format, isSameMonth, startOfMonth, subMonths } from 'date-fns';
4	import { AppDataSource } from '../data-source';
5	import { loadConfig } from '../config/env';
6	import { FinancialRecord } from '../entities/financial-record.entity';
7	import { getRecommendations } from './recommendations.service';
8	
9	export type FinancialHealthColour = 'green' | 'amber' | 'red';
10	export type FinancialHealthRating = FinancialHealthColour;
11	
12	export interface FinancialHealthSummary {
13	  rating: FinancialHealthRating;
14	  income: number;
15	  essentialSpend: number;
16	  debtRepayments: number;
17	  discretionarySpend: number;
18	  surplusAfterEssentials: number;
19	  headroom: number;
20	  headroomRatio: number;
21	  // What's truly left over after every outgoing this month — the "leftover"
22	  // figure surfaced in the financial-health widget. Mirrors the per-month
23	  // disposable-income calculation used by the over-time-progress widget so the
24	  // two widgets reconcile.
25	  disposableIncome: number;
26	}
27	
28	export type FinancialHealthBadgeTone = 'success' | 'warning' | 'danger';
29	
30	export interface FinancialHealthStatus extends FinancialHealthSummary {
31	  badgeLabel: string;
32	  badgeTone: FinancialHealthBadgeTone;
33	  headline: string;
34	  body: string;
35	}
36	
37	export interface DiscretionaryItem {
38	  description: string;
39	  amount: number;
40	}
41	
42	export type ProgressPoint = {
43	  period: string;
44	  progress: number;
45	  disposable_income: number;
46	  is_now: boolean;
47	};
48	
49	export type OverTimeProgressOptions = {
50	  userId: string;
51	  month?: number;
52	  year?: number;
53	};
54	
55	export type YourMoneyItem = {
56	  description: string;
57	  amount: number;
58	};
59	
60	export type YourMoneySection = {
61	  sectionKey: string;
62	  sectionLabel: string;
63	  subtotal: number;
64	  items: YourMoneyItem[];
65	};
66	
67	export type YourMoneyGroup = {
68	  total: number;
69	  sections: YourMoneySection[];
70	};
71	
72	export type YourMoneyThisMonth = {
73	  income: YourMoneyGroup;
74	  outgoing: YourMoneyGroup;
75	};
76	
77	export type YourMoneyThisMonthOptions = OverTimeProgressOptions;
78	
79	export type Dashboard = {
80	  overTimeProgress: ProgressPoint[];
81	  yourMoneyThisMonth: YourMoneyThisMonth;
82	  financialHealthStatus: FinancialHealthStatus;
83	  recommendations: string[];
84	};
85	
86	export type DashboardOptions = OverTimeProgressOptions;
87	
88	type MonthBucket = {
89	  monthStart: UTCDate;
90	  totalIncome: number;
91	  totalExpenditure: number;
92	};
93	
94	const getRepository = (): Repository<FinancialRecord> =>
95	  AppDataSource.getRepository(FinancialRecord);
96	
97	const formatPeriod = (date: Date): string => format(date, 'MMM yyyy');
98	
99	// Progress is a 0–100 score representing where a month sits within the
100	// disposable-income range of the current window: best month → 100, worst → 0.
101	// It is intentionally relative — it surfaces the customer's own trajectory
102	// rather than judging them against an absolute threshold.
103	export const calculateProgressForWindow = (disposableIncomes: number[]): number[] => {
104	  if (disposableIncomes.length === 0) {
105	    return [];
106	  }
107	  if (disposableIncomes.length === 1) {
108	    return [disposableIncomes[0] > 0 ? 100 : 0];
109	  }
110	  const min = Math.min(...disposableIncomes);
111	  const max = Math.max(...disposableIncomes);
112	  if (min === max) {
113	    return disposableIncomes.map(() => 50);
114	  }
115	  const range = max - min;
116	  return disposableIncomes.map((d) => Math.round(((d - min) / range) * 100));
117	};
118	
119	const initBuckets = (mostRecentMonth: UTCDate, lookbackMonths: number): MonthBucket[] => {
120	  const oldestMonth = subMonths(mostRecentMonth, lookbackMonths - 1);
121	  return Array.from({ length: lookbackMonths }, (_, offset) => ({
122	    monthStart: addMonths(oldestMonth, offset),
123	    totalIncome: 0,
124	    totalExpenditure: 0,
125	  }));
126	};
127	
128	const bucketKey = (date: Date): string => format(date, 'yyyy-MM');
129	
130	export const getOverTimeProgress = async (
131	  options: OverTimeProgressOptions,
132	): Promise<ProgressPoint[]> => {
133	  const config = loadConfig();
134	  const lookbackMonths = config.progressLookbackMonths;
135	  const now = new UTCDate();
136	  const currentMonthStart = startOfMonth(now);
137	
138	  let targetMonthStart = currentMonthStart;
139	  if (options.month && options.year) {
140	    targetMonthStart = startOfMonth(new UTCDate(options.year, options.month - 1, 1));
141	  }
142	
143	  const buckets = initBuckets(targetMonthStart, lookbackMonths);
144	
145	  const windowStart = buckets[0].monthStart;
146	  const windowEnd = endOfMonth(buckets[buckets.length - 1].monthStart);
147	
148	  const records = await getRepository().find({
149	    where: {
150	      userId: options.userId,
151	      transactionDate: Between(windowStart, windowEnd),
152	    },
153	  });
154	
155	  const bucketIndex = new Map<string, MonthBucket>();
156	  for (const bucket of buckets) {
157	    bucketIndex.set(bucketKey(bucket.monthStart), bucket);
158	  }
159	
160	  for (const record of records) {
161	    const bucket = bucketIndex.get(bucketKey(new UTCDate(record.transactionDate)));
162	    if (!bucket) {
163	      continue;
164	    }
165	    const amount = Number(record.amount);
166	    if (record.type === 'income') {
167	      bucket.totalIncome += amount;
168	    } else {
169	      bucket.totalExpenditure += amount;
170	    }
171	  }
172	
173	  // Buckets are built oldest → most recent for chronological aggregation;
174	  // the API returns them most recent → oldest so consumers can render the
175	  // newest period at the top of a list without re-sorting.
176	  const orderedBuckets = buckets.reverse();
177	  const disposableIncomes = orderedBuckets.map(
178	    (bucket) => bucket.totalIncome - bucket.totalExpenditure,
179	  );
180	  const progresses = calculateProgressForWindow(disposableIncomes);
181	
182	  return orderedBuckets.map((bucket, index) => ({
183	    period: formatPeriod(bucket.monthStart),
184	    progress: progresses[index],
185	    disposable_income: disposableIncomes[index],
186	    is_now: isSameMonth(bucket.monthStart, currentMonthStart),
187	  }));
188	};
189	
190	const INCOME_SECTION_KEY = 'income';
191	const INCOME_SECTION_LABEL = 'Income';
192	const UNCATEGORISED_SECTION_KEY = 'other';
193	const UNCATEGORISED_SECTION_LABEL = 'Other';
194	
195	const round2 = (value: number): number => Math.round(value * 100) / 100;
196	
197	// Convert kebab-case (the storage shape of `type_category`) to the two
198	// presentation forms the response needs. Doing it here means a future enum
199	// value lights up the whole response without touching this file.
200	const kebabToCamel = (value: string): string =>
201	  value
202	    .split('-')
203	    .filter(Boolean)
204	    .map((part, index) => (index === 0 ? part : part.charAt(0).toUpperCase() + part.slice(1)))
205	    .join('');
206	
207	const kebabToTitle = (value: string): string =>
208	  value
209	    .split('-')
210	    .filter(Boolean)
211	    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
212	    .join(' ');
213	
214	const sectionKeyForRecord = (record: FinancialRecord): string => {
215	  if (record.type === 'income') return INCOME_SECTION_KEY;
216	  if (!record.typeCategory) return UNCATEGORISED_SECTION_KEY;
217	  return kebabToCamel(record.typeCategory);
218	};
219	
220	const sectionLabelForRecord = (record: FinancialRecord): string => {
221	  if (record.type === 'income') return INCOME_SECTION_LABEL;
222	  if (!record.typeCategory) return UNCATEGORISED_SECTION_LABEL;
223	  return kebabToTitle(record.typeCategory);
224	};
225	
226	export const getYourMoneyThisMonth = async (
227	  options: YourMoneyThisMonthOptions,
228	): Promise<YourMoneyThisMonth> => {
229	  const now = new UTCDate();
230	  const targetMonthStart =
231	    options.month && options.year
232	      ? startOfMonth(new UTCDate(options.year, options.month - 1, 1))
233	      : startOfMonth(now);
234	  const targetMonthEnd = endOfMonth(targetMonthStart);
235	
236	  const records = await getRepository().find({
237	    where: {
238	      userId: options.userId,
239	      transactionDate: Between(targetMonthStart, targetMonthEnd),
240	    },
241	    order: { transactionDate: 'ASC', id: 'ASC' },
242	  });
243	
244	  const buckets: Record<'income' | 'outgoing', Map<string, YourMoneySection>> = {
245	    income: new Map(),
246	    outgoing: new Map(),
247	  };
248	  const totals: Record<'income' | 'outgoing', number> = {
249	    income: 0,
250	    outgoing: 0,
251	  };
252	
253	  for (const record of records) {
254	    const amount = Number(record.amount);
255	    totals[record.type] = round2(totals[record.type] + amount);
256	
257	    const key = sectionKeyForRecord(record);
258	    let section = buckets[record.type].get(key);
259	    if (!section) {
260	      section = {
261	        sectionKey: key,
262	        sectionLabel: sectionLabelForRecord(record),
263	        subtotal: 0,
264	        items: [],
265	      };
266	      buckets[record.type].set(key, section);
267	    }
268	    section.subtotal = round2(section.subtotal + amount);
269	
270	    // Aggregate items sharing a description so the widget shows one row per
271	    // recurring entry (e.g. two "Salary" records sum to a single "Salary" line).
272	    const existingItem = section.items.find((i) => i.description === record.description);
273	    if (existingItem) {
274	      existingItem.amount = round2(existingItem.amount + amount);
275	    } else {
276	      section.items.push({ description: record.description, amount });
277	    }
278	  }
279	
280	  const buildGroup = (type: 'income' | 'outgoing'): YourMoneyGroup => {
281	    const sections = Array.from(buckets[type].values()).sort((a, b) =>
282	      a.sectionKey.localeCompare(b.sectionKey),
283	    );
284	    for (const section of sections) {
285	      // Largest amount first within a section; alphabetical tiebreaker keeps
286	      // the order deterministic across runs.
287	      section.items.sort((a, b) => {
288	        if (b.amount !== a.amount) return b.amount - a.amount;
289	        return a.description.localeCompare(b.description);
290	      });
291	    }
292	    return { total: totals[type], sections };
293	  };
294	
295	  return {
296	    income: buildGroup('income'),
297	    outgoing: buildGroup('outgoing'),
298	  };
299	};
300	
301	// Spec-defined thresholds for the headroom-ratio rating. Kept here (not in env)
302	// because changing them changes the meaning of the rating, not just a knob.
303	const HEADROOM_RATIO_AMBER_FLOOR = 0.1;
304	const HEADROOM_RATIO_GREEN_FLOOR = 0.2;
305	
306	export interface HealthInputRecord {
307	  type: 'income' | 'outgoing';
308	  typeCategory: 'essential' | 'debt-repayment' | 'discretionary' | null;
309	  amount: number;
310	}
311	
312	export const calculateFinancialHealth = (records: HealthInputRecord[]): FinancialHealthSummary => {
313	  let income = 0;
314	  let essentialSpend = 0;
315	  let debtRepayments = 0;
316	  let discretionarySpend = 0;
317	
318	  for (const record of records) {
319	    const amount = Number(record.amount);
320	    if (record.type === 'income') {
321	      income += amount;
322	      continue;
323	    }
324	    if (record.typeCategory === 'essential') {
325	      essentialSpend += amount;
326	    } else if (record.typeCategory === 'debt-repayment') {
327	      debtRepayments += amount;
328	    } else {
329	      // Anything else outgoing — explicit "discretionary" or uncategorised — is
330	      // treated as discretionary. Uncategorised outgoings are negotiable by
331	      // default; if the user wants them protected they should categorise them.
332	      discretionarySpend += amount;
333	    }
334	  }
335	
336	  const surplusAfterEssentials = income - essentialSpend;
337	  const headroom = surplusAfterEssentials - debtRepayments;
338	  const headroomRatio = income > 0 ? headroom / income : 0;
339	
340	  let rating: FinancialHealthRating;
341	  if (income <= 0 || essentialSpend > income) {
342	    rating = 'red';
343	  } else if (headroom <= 0) {
344	    rating = 'red';
345	  } else if (headroomRatio < HEADROOM_RATIO_AMBER_FLOOR) {
346	    rating = 'red';
347	  } else if (headroomRatio < HEADROOM_RATIO_GREEN_FLOOR) {
348	    rating = 'amber';
349	  } else {
350	    rating = 'green';
351	  }
352	
353	  const disposableIncome = income - essentialSpend - debtRepayments - discretionarySpend;
354	
355	  return {
356	    rating,
357	    income: round2(income),
358	    essentialSpend: round2(essentialSpend),
359	    debtRepayments: round2(debtRepayments),
360	    discretionarySpend: round2(discretionarySpend),
361	    surplusAfterEssentials: round2(surplusAfterEssentials),
362	    headroom: round2(headroom),
363	    headroomRatio: Math.round(headroomRatio * 10000) / 10000,
364	    disposableIncome: round2(disposableIncome),
365	  };
366	};
367	
368	// Rating-keyed copy lives on the backend so messaging stays consistent across
369	// surfaces and can be tweaked without a frontend deploy. Tone is included so
370	// the widget renders the same colour treatment everywhere.
371	const HEALTH_STATUS_COPY: Record<
